import '../lib/daily_window.dart';
import '../lib/offset_schedule.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final transition = DateTime.utc(2026, 3, 8, 10);
  final offsets = OffsetSchedule(const Duration(hours: -8), <OffsetChange>[
    OffsetChange(transition, const Duration(hours: -7)),
  ]);

  check(
    offsets.offsetAt(transition) == const Duration(hours: -7),
    'the new offset starts at the transition instant',
  );

  final scheduler = DailyWindowScheduler(offsets);
  check(
    scheduler.nextRun(DateTime.utc(2026, 3, 7, 20), hour: 9, minute: 0) ==
        DateTime.utc(2026, 3, 8, 16),
    'the next wall-clock run uses the offset in effect at that run',
  );

  print('feedback tests passed');
}
